\documentclass[11pt,a4paper]{article}
\usepackage[utf8]{inputenc}
\usepackage{amsmath,amssymb,amsthm}
\usepackage{booktabs}
\usepackage{hyperref}
\usepackage[margin=1in]{geometry}
\usepackage{natbib}

\title{A numerical note on the $(c,b,t)$ Koide combination at lepton-derived scales}
\author{Andrew M.~Brilliant\\
\small Applied Dynamics Research, Sapporo, Japan\\
\small \texttt{ab@ad-research.org}}
\date{April 15, 2026}

\begin{document}
\maketitle

\begin{abstract}
The Koide combination $Q = (\sum m)/(\sum \sqrt{m})^2 = 2/3$ holds for the charged lepton pole masses to one part in $10^5$. For the heavy quark triple $(c,b,t)$ in the $\overline{\text{MS}}$ scheme at all self-scales, $Q = 0.662020$, a residual of $-4.65\times10^{-3}$ from $2/3$, indicating that $Q$ must increase to close. In a companion paper we observed that the squared outer Soddy curvature of the lepton triple equals the strange-quark $\overline{\text{MS}}$ mass at the lepton-sum scale $\Sigma m_\ell$. Here we examine whether a similar pattern appears in the heavy sector.

We work in $\overline{\text{MS}}$ and consider only physically motivated scale choices. The top mass can only be evaluated at its self-scale (no heavier SM particle). For bottom, alternative scales ($M_W$, $M_Z$, $m_H$) lie within its perturbative window but they all \emph{decrease} $Q$, moving away from $2/3$; they are therefore not candidates for a consistency check that aims to close the relation. For charm, the only SM particle masses inside its window $[m_c, m_b]$ besides its self-scale are $m_\tau$ and $\Sigma m_\ell$. Thus, besides the all-self-scales case, there are exactly two alternative prescriptions that respect both the perturbative window and the direction of the required correction.

Running $m_c$ via four-loop $\overline{\text{MS}}$ to $\mu = m_\tau$ yields $Q = 0.666718$, a residual of $+5.10\times10^{-5}$ from $2/3$, well below the propagated input uncertainty $\sigma_Q \approx 5.4\times10^{-4}$ (dominated by the PDG uncertainty on $m_t$). The other natural alternative ($m_c$ at $\Sigma m_\ell$) gives a residual $+7.47\times10^{-4}$, two orders of magnitude larger. We report this as a numerical observation parallel to the strange-quark case. No mechanism is proposed, and the residual lies within the measurement precision, so the relation is consistent with $2/3$ exactly but also with a range of values.
\end{abstract}

\section{Introduction}

The Koide relation \citep{Koide1982,Koide1983}
\begin{equation}
Q \equiv \frac{m_e + m_\mu + m_\tau}{\bigl(\sqrt{m_e} + \sqrt{m_\mu} + \sqrt{m_\tau}\bigr)^2} = \frac{2}{3}
\end{equation}
holds for the charged lepton pole masses to a residual of $-6.16\times10^{-6}$. Extensions to the quark sector \citep{Rivero2011} have noted that the heavy triple $(c,b,t)$ in the $\overline{\text{MS}}$ scheme at all self-scales gives
\begin{equation}
Q(c,b,t)\big|_{\text{all self-scales}} = 0.6620198,\qquad \text{residual} = -4.65\times10^{-3},
\end{equation}
a known near-miss whose sign indicates that $Q$ must increase to close.

In a companion paper \citep{BrilliantStrange2026} we observed that the squared outer Soddy curvature of the lepton triple matches the strange-quark $\overline{\text{MS}}$ mass at the lepton-sum scale $\mu_\star = m_e+m_\mu+m_\tau$ within current lattice precision. That observation involved a lepton-derived scale entering a quark-sector relation. The present note asks whether a similar pattern appears in the heavy quark sector, specifically for the $(c,b,t)$ Koide combination.

\section{Setup}

We work in the $\overline{\text{MS}}$ scheme throughout. Inputs are taken from PDG 2024 \citep{PDG2024} and FLAG 2024 \citep{FLAG2024}:
\begin{itemize}
\item $m_c(m_c) = 1.2807 \pm 0.0013$~GeV,
\item $m_b(m_b) = 4.203 \pm 0.011$~GeV,
\item $m_t(m_t) = 162.5 \pm 0.7$~GeV (converted from the pole mass using four-loop running \citep{Marquard2015}),
\item $\alpha_s(M_Z) = 0.1180 \pm 0.0009$,
\item $m_e = 0.5109989461$~MeV, $m_\mu = 105.6583755$~MeV, $m_\tau = 1776.86 \pm 0.12$~MeV,
\item $M_W = 80.369$~GeV, $M_Z = 91.1876$~GeV, $m_H = 125.25$~GeV.
\end{itemize}
All quark masses are $\overline{\text{MS}}$. Running between scales is performed via four-loop QCD using \texttt{CRunDec} \citep{CRunDec}, with full threshold matching at $m_c(m_c)$, $m_b(m_b)$, and $m_t(m_t)$. The Koide combination is
\begin{equation}
Q(c,b,t)(\mu_c,\mu_b,\mu_t) = \frac{m_c(\mu_c) + m_b(\mu_b) + m_t(\mu_t)}{\bigl(\sqrt{m_c(\mu_c)} + \sqrt{m_b(\mu_b)} + \sqrt{m_t(\mu_t)}\bigr)^2}.
\end{equation}

\section{Motivation for scale choices}

For a consistency check that aims to close the known near-miss, we require that any alternative scale assignment should (i) lie within the perturbative running window of the respective quark (where the $\overline{\text{MS}}$ definition is most reliable), and (ii) move $Q$ toward $2/3$ (i.e., increase $Q$ from its all-self-scales value).

\paragraph{Top.} The running window of the top quark is $[m_t(m_t), \infty)$. No Standard Model particle has a rest mass above $m_t$. Hence the only possible scale for $m_t$ is its self-scale $m_t(m_t)$. Top therefore plays no role in varying the combination.

\paragraph{Bottom.} The running window of the bottom quark is $[m_b(m_b), m_t(m_t)] = [4.20, 162.5]$~GeV. Standard Model particles in this window are $M_W = 80.369$~GeV, $M_Z = 91.188$~GeV, and $m_H = 125.25$~GeV. Evaluating $m_b$ at any of these boson scales \emph{decreases} $m_b$ (e.g., from $4.20$~GeV to $\approx 2.85$~GeV at $M_W$). A smaller $m_b$ in the Koide combination \emph{lowers} $Q$ (because the denominator contains $\sqrt{m_b}$ and the numerator contains $m_b$; the net effect is to move $Q$ further from $2/3$). Thus none of the bottom-alternative scales satisfies condition (ii). Bottom is therefore also fixed to its self-scale for our purpose.

\paragraph{Charm.} The running window of the charm quark is $[m_c(m_c), m_b(m_b)] = [1.28, 4.20]$~GeV. Standard Model particle masses in this window are $m_\tau = 1.77686$~GeV and $\Sigma m_\ell = m_e+m_\mu+m_\tau = 1.88303$~GeV (the charged-lepton sum). Both lie inside the window. Running $m_c$ to a higher scale (from $1.28$~GeV to $\approx 1.14$–$1.12$~GeV) \emph{decreases} $m_c$, which increases $Q$ (the denominator contains $\sqrt{m_c}$ and the numerator contains $m_c$; the net effect for the heavy triple is to raise $Q$). Hence charm is the only quark whose variation can move $Q$ toward $2/3$, and there are exactly two physically motivated alternative scales to consider besides its self-scale: $m_\tau$ and $\Sigma m_\ell$.

Thus, besides the all-self-scales prescription, there are exactly two alternative prescriptions that respect both the perturbative window and the direction of the required correction:
\begin{enumerate}
\item $m_c$ evaluated at $\mu = m_\tau$, with $m_b$ and $m_t$ at their self-scales;
\item $m_c$ evaluated at $\mu = \Sigma m_\ell$, with $m_b$ and $m_t$ at their self-scales.
\end{enumerate}
We compute both.

\section{Results}

Table~\ref{tab:results} shows the three charm-scale prescriptions (self-scale, $m_\tau$, $\Sigma m_\ell$). The all-self-scales case is included as a baseline.

\begin{table}[h]
\centering
\small
\begin{tabular}{lllc}
\toprule
$\mu_c$ (GeV) & $m_c(\mu_c)$ (GeV) & $Q(c,b,t)$ & residual vs $2/3$ \\
\midrule
$m_c(m_c) = 1.281$ & $1.28070$ & $0.6620198$ & $-4.65\times10^{-3}$ \\
$m_\tau = 1.777$    & $1.14262$ & $0.6667177$ & $+5.10\times10^{-5}$ \\
$\Sigma m_\ell = 1.883$ & $1.12304$ & $0.6674137$ & $+7.47\times10^{-4}$ \\
\bottomrule
\end{tabular}
\caption{Koide combination $Q(c,b,t)$ for three charm-scale prescriptions. In all cases $m_b$ and $m_t$ are at their self-scales. The $m_\tau$ prescription yields a residual two orders of magnitude smaller than the $\Sigma m_\ell$ prescription and an order of magnitude below the propagated uncertainty (see Section~\ref{sec:budget}).}
\label{tab:results}
\end{table}

The $m_\tau$ prescription gives $Q = 0.6667177$, a residual of $+5.10\times10^{-5}$ from $2/3 = 0.6666667$. The $\Sigma m_\ell$ prescription gives a residual $+7.47\times10^{-4}$, about $15$ times larger. The all-self-scales residual is $-4.65\times10^{-3}$, two orders of magnitude larger in absolute value.

\section{Uncertainty budget}
\label{sec:budget}

We propagate the input uncertainties independently through the four-loop running and the Koide combination to obtain the contribution of each source to $\sigma_Q$ at the $m_\tau$ prescription. Table~\ref{tab:budget} shows the decomposition.

\begin{table}[h]
\centering
\begin{tabular}{lcc}
\toprule
Source & $\sigma$ contribution to $Q$ & Fraction of total variance \\
\midrule
FLAG $m_c(m_c) = 1.2807 \pm 0.0013$~GeV & $4.10\times10^{-5}$ & 0.65\% \\
FLAG $m_b(m_b) = 4.203 \pm 0.011$~GeV   & $1.82\times10^{-4}$ & 12.8\% \\
PDG $m_t(m_t) = 162.5 \pm 0.7$~GeV       & $4.73\times10^{-4}$ & 86.4\% \\
$\alpha_s(M_Z) = 0.1180 \pm 0.0009$       & $1.78\times10^{-4}$ & (separate) \\
\midrule
Quadrature sum (quark masses + $\alpha_s$) & $5.39\times10^{-4}$ & \\
\bottomrule
\end{tabular}
\caption{Decomposition of $\sigma_Q$ at $\mu_c = m_\tau$ under independent variation of each input. The PDG uncertainty on $m_t$ dominates. Systematic uncertainties from perturbative truncation, scheme dependence, and the pole-to-$\overline{\text{MS}}$ conversion of $m_t$ are not included; the reported $\sigma_Q$ is therefore a lower bound.}
\label{tab:budget}
\end{table}

The total propagated uncertainty is $\sigma_Q \approx 5.4\times10^{-4}$. The observed residual at the $m_\tau$ prescription is $+5.10\times10^{-5}$, approximately one order of magnitude smaller than $\sigma_Q$. This means the value of $Q$ is consistent with $2/3$ exactly, but also with any other value within the propagated band. We do not claim the relation is exact; we report the numerical near-coincidence as an observation.

\section{Caveats}

We make the following limitations explicit.

\paragraph{The observation is conditioned on the specific scale choices.} The selection of charm as the only varied quark is motivated by the sign of the required correction and by the absence of alternative scales for top and bottom that move $Q$ toward $2/3$. This is a physically transparent but post-hoc choice; we do not present it as a pre-registered test.

\paragraph{The residual lies within input uncertainty.} The residual of $+5.10\times10^{-5}$ is smaller than $\sigma_Q$, so the result is compatible with $Q = 2/3$ exactly, but also with a range of other values. No statistical significance is claimed.

\paragraph{Not a derivation or mechanism.} We have not derived the relation from a Lagrangian or symmetry. The inputs were all known before this calculation. We offer no mechanism.

\paragraph{$\overline{\text{MS}}$-specific.} The result uses the $\overline{\text{MS}}$ scheme. Robustness across alternative heavy-quark mass schemes (1S, PS, MSR, kinetic) has not been tested.

\section{Discussion}

The companion paper \citep{BrilliantStrange2026} reported that the squared outer Soddy curvature of the lepton triple matches $m_s^{\overline{\text{MS}}}$ at the lepton-sum scale $\Sigma m_\ell$. The present note finds that for the heavy $(c,b,t)$ Koide combination, evaluating $m_c$ at $m_\tau$ brings $Q$ to within $5\times10^{-5}$ of $2/3$, while the other natural charm-scale alternative ($\Sigma m_\ell$) gives a residual two orders of magnitude larger. The two observations involve different lepton-derived scales ($\Sigma m_\ell$ for strange, $m_\tau$ for charm) and different algebraic structures (Soddy curvature vs. Koide combination). 

Whether this pattern is accidental or points to an underlying relation is not settled by the present work. The narrowness of the observed near-coincidence (one of three natural charm-scale prescriptions, with the other two giving residuals orders of magnitude larger) is a numerical fact; its interpretation is left to future theoretical investigation.

\section*{Computational note}

All computations are reproducible from the accompanying GitHub repository \citep{RepoHeavy}. Four-loop $\overline{\text{MS}}$ running is performed via \texttt{CRunDec} \citep{CRunDec} with $\alpha_s(M_Z) = 0.1180$ and full threshold matching at $m_c(m_c)$, $m_b(m_b)$, and $m_t(m_t)$. Total runtime is under one minute.

